  end

  defp process_soap_action(%{name: action_name}, _doc) do
    {:error, "Unknown SOAP action: #{action_name}"}
  end

  defp build_soap_fault(fault_code, fault_string) do
    """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Body>
        <soap:Fault>
          <faultcode>soap:#{escape_xml(to_string(fault_code))}</faultcode>
